macro.command:
const version = "13.0.52";
try {
    const lastArg = args[args.length - 1];
    if (args[0] === "on") {
        const caster = macroItem?.actor;
        if (!caster) return;
        const targetEffect = actor.effects.get(lastArg.effectId);
        if (!targetEffect) return;
        const linkEffects = async (mirroredEffect) => {
            await mirroredEffect.update({"flags.dnd5e.dependentOn": targetEffect.uuid});
            await targetEffect.update({"flags.dnd5e.dependentOn": mirroredEffect.uuid});
        };
        const mirrored = caster.appliedEffects.find(e => e.name === "Bonded" && e.origin?.includes(macroItem.uuid));
        if (mirrored) {
            await linkEffects(mirrored);
        } else {
            const hookId = Hooks.on("createActiveEffect", async (effect) => {
                if (effect.parent !== caster || !effect.origin?.includes(macroItem.uuid)) return;
                Hooks.off("createActiveEffect", hookId);
                await linkEffects(effect);
            });
            setTimeout(() => Hooks.off("createActiveEffect", hookId), 10000);
        }
        return;
    }
    // Check >60ft separation — ends the spell
    if (lastArg.sourceToken && lastArg.targetToken) {
        const distance = MidiQOL.computeDistance(lastArg.sourceToken, lastArg.targetToken, {wallsBlock: false});
        if (distance > 60) {
            await ChatMessage.create({content: `${macroItem.name} ends — caster and target are more than 60 feet apart (${distance} ft).`});
            const effectToDelete = lastArg.actor?.appliedEffects.find(e => e.name === "Bonded" && e.origin?.includes(macroItem.uuid));
            if (effectToDelete) await effectToDelete.delete();
            return;
        }
    }
    const newHp = foundry.utils.getProperty(lastArg.updates, "system.attributes.hp.value");
    if (newHp === undefined) return;
    const isCasterUpdate = lastArg.actor === macroItem?.actor;
    if (!isCasterUpdate) {
        const oldHp = lastArg.actor.system.attributes.hp.value;
        if (newHp < oldHp) {
            const damage = oldHp - newHp;
            await ChatMessage.create({content: `${macroItem.name} deals ${damage} damage to ${lastArg.sourceActor.name}`});
            MidiQOL.applyTokenDamage([{damage: damage, type: "none"}], damage, new Set([lastArg.sourceToken]), undefined, new Set(), {existingDamage: [], superSavers: new Set(), semiSuperSavers: new Set(), workflow: undefined, updateContext: {onUpdateCalled: true}});
        }
    } else if (newHp <= 0) {
        const casterEffect = lastArg.actor?.appliedEffects.find(e => e.name === "Bonded" && e.origin?.includes(macroItem.uuid));
        if (casterEffect) await casterEffect.delete();
    }
} catch (err) {
    console.error(`Warding Bond ${version}`, err);
}
